body {
  font-family: system-ui, sans-serif;
  margin: 0;
  padding: 1.5rem;
  line-height: 1.6;
  max-width: 42rem;
  color: #334155;
  background: #f8fafc;
}

header {
  margin-bottom: 1rem;
}

h1 {
  color: #2563eb;
  margin: 0 0 0.25rem;
  font-size: 1.75rem;
}

header h2 {
  color: #64748b;
  font-size: 1.1rem;
  font-weight: 600;
  margin: 0;
}

img {
  display: block;
  max-width: 220px;
  width: 100%;
  height: auto;
  border-radius: 12px;
  margin-bottom: 1rem;
  border: 3px solid #dbeafe;
}

.videos h2 {
  color: #1e40af;
  font-size: 1.15rem;
  margin: 1.5rem 0 0.75rem;
}

.video-wrap {
  margin-bottom: 1rem;
}

.video-wrap iframe {
  width: 100%;
  max-width: 560px;
  aspect-ratio: 16 / 9;
  height: auto;
  border: 0;
  border-radius: 8px;
}

footer {
  margin-top: 2rem;
  padding-top: 1rem;
  border-top: 1px solid #e2e8f0;
  font-size: 0.9rem;
  color: #64748b;
}

footer p {
  margin: 0;
}

